Example: Indications¶frommanimimport*classIndications(Scene):defconstruct(self):indications=[ApplyWave,Circumscribe,Flash,FocusOn,Indicate,ShowPassingFlash,Wiggle]names=[Tex(i.__name__).scale(3)foriinindications]self.add(names[0])foriinrange(len(names)):ifindications[i]isFlash:self.play(Flash(UP))elifindications[i]isShowPassingFlash:self.play(ShowPassingFlash(Underline(names[i])))else:self.play(indications[i](names[i]))self.play(AnimationGroup(FadeOut(names[i],shift=UP*1.5),FadeIn(names[(i+1)%len(names)],shift=UP*1.5),))class Indications(Scene):
    def construct(self):
        indications = [ApplyWave,Circumscribe,Flash,FocusOn,Indicate,ShowPassingFlash,Wiggle]
        names = [Tex(i.__name__).scale(3) for i in indications]

        self.add(names[0])
        for i in range(len(names)):
            if indications[i] is Flash:
                self.play(Flash(UP))
            elif indications[i] is ShowPassingFlash:
                self.play(ShowPassingFlash(Underline(names[i])))
            else:
                self.play(indications[i](names[i]))
            self.play(AnimationGroup(
                FadeOut(names[i], shift=UP*1.5),
                FadeIn(names[(i+1)%len(names)], shift=UP*1.5),
            ))

Example: HomotopyExample¶frommanimimport*classHomotopyExample(Scene):defconstruct(self):square=Square()defhomotopy(x,y,z,t):ift<=0.25:progress=t/0.25return(x,y+progress*0.2*np.sin(x),z)else:wave_progress=(t-0.25)/0.75return(x,y+0.2*np.sin(x+10*wave_progress),z)self.play(Homotopy(homotopy,square,rate_func=linear,run_time=2))class HomotopyExample(Scene):
    def construct(self):
        square = Square()

        def homotopy(x, y, z, t):
            if t <= 0.25:
                progress = t / 0.25
                return (x, y + progress * 0.2 * np.sin(x), z)
            else:
                wave_progress = (t - 0.25) / 0.75
                return (x, y + 0.2 * np.sin(x + 10 * wave_progress), z)

        self.play(Homotopy(homotopy, square, rate_func= linear, run_time=2))

