Example: AnimationOverrideExample¶frommanimimport*classCircleWithContent(VGroup):def__init__(self,content):super().__init__()self.circle=Circle()self.content=contentself.add(self.circle,content)content.move_to(self.circle.get_center())defclear_content(self):self.remove(self.content)self.content=None@override_animate(clear_content)def_clear_content_animation(self,anim_args=None):ifanim_argsisNone:anim_args={}anim=Uncreate(self.content,**anim_args)self.clear_content()returnanimclassAnimationOverrideExample(Scene):defconstruct(self):t=Text("hello!")my_mobject=CircleWithContent(t)self.play(Create(my_mobject))self.play(my_mobject.animate.clear_content())self.wait()class CircleWithContent(VGroup):
    def __init__(self, content):
        super().__init__()
        self.circle = Circle()
        self.content = content
        self.add(self.circle, content)
        content.move_to(self.circle.get_center())

    def clear_content(self):
        self.remove(self.content)
        self.content = None

    @override_animate(clear_content)
    def _clear_content_animation(self, anim_args=None):
        if anim_args is None:
            anim_args = {}
        anim = Uncreate(self.content, **anim_args)
        self.clear_content()
        return anim

